            }
        }
        CellPatch ghost;
        memset(&ghost, 0, sizeof(ghost));
        op_b(&ghost, &src, k, 1);
        for (int v = 0; v < NVAR; v++) st->halo_q[v] = ghost.q[v];
    }

    if (!spec->do_collapse) return;

    CellGrid folded;
    folded.n = 0;
